// src/api/axiosClient.js
// Cliente Axios con la URL base del backend.
// El interceptor adjunta automáticamente el token JWT a cada petición.

import axios from 'axios'

const axiosClient = axios.create({
  baseURL: 'http://localhost:4000/api',
  headers: { 'Content-Type': 'application/json' },
})

// Antes de cada petición, adjunta el token si existe
axiosClient.interceptors.request.use((config) => {
  const token = localStorage.getItem('token')
  if (token) config.headers.Authorization = `Bearer ${token}`
  return config
})

// Si el backend responde 401, limpia la sesión
axiosClient.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('token')
      localStorage.removeItem('user')
      window.location.href = '/login'
    }
    return Promise.reject(err)
  }
)

export default axiosClient
